+func TestFindOrphanedDatabases_IgnoresNonDoltDirs(t *testing.T) {
+	townRoot := t.TempDir()
+	dataDir := filepath.Join(townRoot, ".dolt-data")
+
+	// Create a referenced database
+	setupDoltDB(t, dataDir, "hq")
+	setupRigsJSON(t, townRoot, []string{})
